from PIL import Imageimport numpy as np# Load the imageimage_path = input("Enter the input path: ")image = Image.open(image_path)# Convert to grayscaleimage = image.convert("L")# Resize for better ASCII representationwidth, height = image.sizeaspect_ratio = height / widthnew_width = 55  # Adjust width for better readabilitynew_height = int(aspect_ratio * new_width)  # Adjust height based on aspect ratioimage = image.resize((new_width, new_height))# Define ASCII characters from darkest to lightest#ascii_chars = "█▉▓▓▊▊▋▌▐▍▍▎▏▒░░⌗⌗##⣿⣿⁛𐄏⢸⢸| 1 "ascii_chars = "█▓▒░░⣿⢸1|!;:. "m = 255 / len(ascii_chars)# Convert pixels to ASCIIpixels = np.array(image)ascii_image = "\n".join(    "".join(ascii_chars[int(pixel // m)] for pixel in row) for row in pixels)# Save ASCII output to fileascii_output_path = input("Enter the output path: ")with open(ascii_output_path, "w") as f:    f.write(ascii_image)